int lastStoneWeight(int* stones, int stonesSize) {
    // Simplified approach using sorting
    while (stonesSize > 1) {
        // Sort in descending order
        for (int i = 0; i < stonesSize - 1; i++) {
            for (int j = i + 1; j < stonesSize; j++) {
                if (stones[i] < stones[j]) {
                    int temp = stones[i];
                    stones[i] = stones[j];
                    stones[j] = temp;
                }
            }
        }

        int first = stones[0];
        int second = stones[1];

        if (first == second) {
            stonesSize -= 2;
            for (int i = 0; i < stonesSize; i++) {
                stones[i] = stones[i + 2];
            }
        } else {
            stones[0] = first - second;
            stonesSize--;
            for (int i = 1; i < stonesSize; i++) {
                stones[i] = stones[i + 1];
            }
        }
    }

    return stonesSize == 0 ? 0 : stones[0];
}

